async function seed() {
    try {
        await mongoose.connect(MONGODB_URI);
        console.log('Connected to MongoDB');

        // Delete existing educational questions to avoid duplicates during testing
        await Question.deleteMany({ board: { $ne: null } });

        await Question.insertMany(questions);
        console.log('✅ Seeded educational questions successfully');

        await mongoose.disconnect();
    } catch (error) {
        console.error('❌ Seeding error:', error);
        process.exit(1);
    }
}

seed();
